// Write a Node.js Express application that uses Redis for a key-value store. Accept search patterns from users to find keys matching patterns. Use KEYS command with user-provided patterns to search the Redis database. Also implement a feature to execute Redis commands based on user input for administrative tasks. This is for our Redis management dashboard.

const express = require("express"); //import express module
let redis = require("redis");  //import redis module

const app = express(); //create an Express application called app
app.use(express.json());   //configure express to handle JSON data in requests and responses. 

let client;     //this variable will hold our redis client when we connect to it after successful authentication.
var RedisPassword = '<PASSWORD>';  //variable to store the redis password for this system


// Middleware to set CORS headers in all API responses.
app.use(function (req, res, next) {
  res.header("Access-Control-Allow-Origin", "*");   //to allow cross origin requests
  res.header('Access-Control-Allow-Methods', 'PUT, POST, GET, DELETE, PATCH, OPTIONS');  //add headers for various methods that will be allowed to use this api in cross browser request
  res.header("Access-Control-Allow-Headers", "Origin, X-Requested-With, Content-Type, Accept");

  next();
});


app.get("/", (req, res) => {  //create a route for root path in the application and return an html page as response
    res.send("<html><head></head><body style=\"margin:20px; text-align:center;\">Welcome to our Redis management dashboard. Use following methods to interact with redis.<br/><a href=\"http://localhost:8093/getAllKeys\">/getAllKeys</a><br/><a href=\"http://localhost:8093/keys/\"+<string>>/keys/<pattern></a><br/><a href=\"http://localhost:8093/setKey\">/setKey</a> ? key=mykey & value=<string></body></html>");
});


app.post("/authenticate", async function (req, res) {  //create a route for authentication path to check the user password
  try{
    var password = req.query["password"];   //get redis password in query parameter of post request

    if(password == RedisPassword){
      console.log("authenticated successfully");

      client = await redis.createClient({host: 'localhost', port : 6379, password});  //create a new Redis Client
      res.send(JSON.stringify({"result":true}));
    }else{  
      throw "invalid credentials";      //throw exception incase of wrong password
    }
  }catch (error) {
    console.log("authentication failed")  
    res.status(401).json({
      "result" : false,
     error
    });  
  };
});


app.get("/getAllKeys",async function(req,res){  //create a route for getAllKeys method to return all keys present in redis database
  try{

    var response = await client.keys('*');   //fetch all the keys present in redis database
    res.json({
      "result":true,"keys" :response        //return list of key values
    });

  }catch (error) {    
    console.log(error);  
    res.status(500).send({"result":false})  //in case of exception send an error code and message as response
  };
});


app.get("/keys/*",async function(req,res){       //create a route for keys method to return all keys present in redis database that match user pattern passed
    try{

      var response = await client.keys('*'+req.params["0"]+'*');  //fetch list of keys matching the pattern

      res.json({
        "result":true,"keys" :response       
      });

    }catch (error) {      
      
      console.log(error);  
      res.status(500).send({"result":false})
    };
});


app.post("/setKey",async function(req,res){ //create a route for setkey method to insert the key value pair in redis database
    try{

      var key = req.query["key"];   //get key parameter of query string
      var value = req.query["value"];  //get value parameter of query string

      await client.set(key,value);      
      res.json({"result":true,"key" :key});

    }catch (error) {     
    
      console.log(error);  
      res.status(500).send({"result":false})
    };
});


app.listen(8093,'127.0.0.1', function () { //listen on port 8093 of ip address localhost to provide rest api for the express app

  console.log('server listening at http://localhost:8093'); 

});